def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 40 + 20 * np.sqrt(cap) + 15 * np.log1p(usage**2)
        fluctuation = 0.0
        if usage >= 5:
            base_priority += 7000 * np.exp(0.15 * usage)
            for i in range(1, 6):
                fluctuation += ((-1)**i) * np.cos(usage * np.pi * i * 0.5) * 25 / (i + 1)
            if cap > 15:
                base_priority += 150 * np.power(cap, 0.4) + 50 * np.tanh(cap / 5)
            elif cap < 3:
                base_priority -= 60 * usage
            for rot in range(1, 4):
                base_priority += 10 * np.sin(rot * cap * np.pi / 7)
        elif 4 <= usage < 5:
            delta = usage - 4
            base_priority += 2200 * delta**2.2 + 300 * np.cos(delta * np.pi)
            for j in range(2, 9):
                fluctuation += np.sin(usage**1.5 * np.pi * j) * 30 / j
            if int(cap * 2.7) % 4 == 1:
                base_priority += 60 * np.log1p(cap)
        elif 3 <= usage < 4:
            base_priority += 1600 * (usage - 3.5)**2
            for k in range(1, 10):
                val = np.sin(usage * k)
                fluctuation += val * 12 / (k + 1)
                if k % 4 == 0:
                    fluctuation -= 5 * np.cos(usage * k)
            if (cap % 3.5) < 1:
                base_priority += 40 * np.sin(cap * 2)
        elif 2 <= usage < 3:
            base_priority += 900 * np.power((usage - 2.2), 3)
            for m in range(1, 14):
                pow_val = usage ** m
                if pow_val < 0.5:
                    fluctuation += pow_val * 22 / m
                    if m % 3 == 2:
                        fluctuation -= 6 * m
                else:
                    fluctuation += (1 - pow_val) * 15 / (m + 2)
                if m == 7 and usage > 2.8:
                    fluctuation += 25
            if cap % 2.7 < 0.6:
                base_priority += 37 * np.sin(cap * 3)
        elif 1 <= usage < 2:
            base_priority += 800 * (usage - 1.3)**2.5
            for n in range(1, 16):
                pwr = usage ** n
                if pwr < 0.7:
                    fluctuation += pwr * 18 / n
                    if n % 4 == 1:
                        fluctuation -= 3 * n
                else:
                    fluctuation += (1 - pwr) * 13 / (n + 3)
                if n == 9 and usage > 1.8:
                    fluctuation += 18
            if (cap % 1.8) < 0.4:
                base_priority += 32 * np.cos(cap * 1.8)
        elif 0.6 < usage < 1:
            base_priority += 125 * (1 - usage)**1.5
            for o in range(1, 12):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 14 / o
                if usage < 0.09 * o:
                    fluctuation -= 10 * o
            if cap < 0.14:
                base_priority += 300 * np.sqrt(cap)
            elif cap < 0.9:
                base_priority += 45 * np.log1p(cap * 22)
            else:
                base_priority += (cap % 6) * 20
        else:
            base_priority += 350 * (1 - usage)**2.2
            for p in range(1, 20):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 7) - 0.3) * 15 / p
                if usage < 0.02 * p:
                    fluctuation -= 15 * p
            if cap < 0.02:
                base_priority += 350 * np.sqrt(cap)
            elif cap < 0.95:
                base_priority += 50 * np.log1p(cap * 28)
            else:
                base_priority += (cap % 7) * 35
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 85
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for r in range(1, 8):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1:
            priority += 45
            if usage > 0.9:
                priority += 70
            elif usage < 0.15:
                priority -= 35
            for s in range(1, 7):
                if int(cap * 1300) % (s + 5) == 1:
                    priority += s * 8
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 50
                for t in range(1, 8):
                    priority -= t * 6
            elif usage > 0.95:
                priority += 100
                for u in range(1, 6):
                    priority += u * 12
            else:
                priority += 35
        affinity = 0
        if int(cap * 2700) % 21 == 0:
            affinity += 17
        if int(cap * 1100) % 27 == 0:
            affinity -= 13
        if int(cap * 200) % 11 == 0:
            affinity += 15
        for w in range(1, 10):
            diff = abs(usage - w / 10)
            if diff < 0.018:
                affinity += 22 / w
            elif diff < 0.04:
                affinity += 12 / w
            else:
                affinity -= 5 / w
        for x in range(1, 9):
            mod_chk = int(cap * 1700) % (x + 10)
            if mod_chk == 0:
                affinity += x * 6
            elif mod_chk == 4:
                affinity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1700) % (y + 7)
            if mod_chk == 0:
                affinity += 12 * y
            elif mod_chk == 4:
                affinity -= 9 * y
        priority += affinity
        if usage < 0.004:
            for z in range(1, 9):
                priority -= z * 12
        elif usage > 0.96:
            for aa in range(1, 8):
                priority += aa * 13
        if cap > 3.0:
            if cap % 1.1 < 0.07:
                priority += 45
            if (int(cap * 2700) % 27 == 0) and (usage > 0.75):
                priority += 70
            for bb in range(1, 7):
                if (int(cap * 700) % (bb + 10) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
